package steps;import lombok.extern.log4j.Log4j2;import pages.LoginPage;import utils.PropertyReader;import static com.codeborne.selenide.Selenide.webdriver;import static com.codeborne.selenide.WebDriverConditions.urlContaining;@Log4j2public class LoginStep {    LoginPage loginPage;    public LoginStep() {        loginPage = new LoginPage();    }    public void auth() {        auth(PropertyReader.getProperty("user"), PropertyReader.getProperty("password"));    }    public void auth(String user, String password) {        log.info("Login with user name '{}' and password '{}'", user, password);        loginPage.open()                .isPageOpened()                .login(user, password);        webdriver().shouldHave(urlContaining("/projects"));    }}